use std::collections::VecDeque;

struct Interpreter<T> {
    input_queue: VecDeque<T>,
}

impl<T: std::fmt::Debug + Clone> Interpreter<T> {
    fn new(initial_inputs: Vec<T>) -> Self {
        Interpreter { 
            input_queue: initial_inputs.into()
        }
    }

    fn process_next(&mut self) -> Option<T> {
        self.input_queue.pop_front()
    }

    fn is_empty(&self) -> bool {
        self.input_queue.is_empty()
    }
}

fn main() {
    let mut interpreter = Interpreter::new(vec![10i32, 5i32]);

    if let Some(result1) = interpreter.process_next() {
        println!("First item processed: {:?}", result1);
    }

    if let Some(result2) = interpreter.process_next() {
        println!("Second item processed: {:?}", result2);
    }

    if interpreter.is_empty() {
        println!("Interpreter queue is now empty.");
    }
}

use std::error::Error;
use std::fmt;

struct ModelConfig<T> {
    weights: T,
    input_size: usize,
}

impl<T: Clone + fmt::Debug> ModelConfig<T> {
    fn new(weights: T, input_size: usize) -> Self {
        ModelConfig { weights, input_size }
    }

    fn run_inference(&self, data: &Vec<f32>) -> Result<f32, Box<dyn Error>> {
        if data.len() != self.input_size {
            return Err(format!("Input size mismatch: expected {}, got {}", self.input_size, data.len()).into());
        }

        let mut sum = 0.0;
        for i in 0..data.len() {
            sum += data[i] as f32 * 0.5; // Simplified calculation based on weight concept
        }
        Ok(sum)
    }
}

fn main() {
    let weights_f32 = vec![1.0, 2.0];
    let config_f32: ModelConfig<Vec<f32>> = ModelConfig::new(weights_f32, 2);
    let input_data_ok = vec![0.5, 1.5];

    match config_f32.run_inference(&input_data_ok) {
        Ok(result) => println!("Inference successful with f32 weights: {}", result),
        Err(e) => eprintln!("Error during f32 inference: {}", e),
    }

    let weights_usize = vec![10, 20];
    let config_usize: ModelConfig<Vec<usize>> = ModelConfig::new(weights_usize, 2);
    let input_data_ok_2 = vec![0.5, 1.5];

    match config_usize.run_inference(&input_data_ok_2) {
        Ok(result) => println!("Inference successful with usize weights (Note: result type might be limited by function scope): {}", result),
        Err(e) => eprintln!("Error during usize inference: {}", e),
    }
}
